    IDENTIFIER = 'IDENTIFIER'
    NUMBER = 'NUMBER'
    STRING = 'STRING'
    OPERATOR = 'OPERATOR'
    PUNCTUATION = 'PUNCTUATION'
    EOF = 'EOF'

