    r'(\d+(?:\.\d+)?)|'  # Numbers
    r'("[^"]*"|\'[^\']*\')|'  # Strings
    r'([a-zA-Z_]\w*)|'  # Identifiers
    r'([=><!]+)|'  # Operators
    r'([,\.()★])',  # Punctuation (★ for *)
    re.IGNORECASE
)

