class Parser:
    def __init__(self, tokens: List[Token]):
        self.tokens = tokens
        self.pos = 0

    def _current(self) -> Token:
        return self.tokens[self.pos]

    def _advance(self) -> Token:
        token = self.tokens[self.pos]
        if self.pos < len(self.tokens) - 1:
            self.pos += 1
        return token

    def _expect(self, token_type: TokenType, value: Any = None) -> Token:
        tok = self._current()
        if tok.type != token_type or (value is not None and tok.value.upper() != str(value).upper()):
            raise SyntaxError(f"Expected {value or token_type.value}, got '{tok.value}' at position {tok.pos}", tok.pos)
        return self._advance()

    def _match(self, value: str) -> bool:
        if self._current().type == TokenType.KEYWORD and self._current().value.upper() == value.upper():
            self._advance()
            return True
        return False

    def parse(self) -> QueryAST:
        ast = QueryAST()
        self._parse_select(ast)
        self._parse_from(ast)
        if self._match('JOIN'):
            self._parse_join(ast)
        if self._match('WHERE'):
            self._parse_where(ast)
        if self._match('GROUP'):
            self._expect(TokenType.KEYWORD, 'BY')
            self._parse_group_by(ast)
        if self._match('ORDER'):
            self._expect(TokenType.KEYWORD, 'BY')
            self._parse_order_by(ast)
        if self._match('LIMIT'):
            self._parse_limit(ast)

        if self._current().type != TokenType.EOF:
            raise SyntaxError(f"Unexpected token '{self._current().value}' at position {self._current().pos}", self._current().pos)
        return ast

    def _parse_select(self, ast: QueryAST):
        self._expect(TokenType.KEYWORD, 'SELECT')
        ast.select.append(self._parse_select_item())
        while self._current().type == TokenType.PUNCTUATION and self._current().value == ',':
            self._advance()
            ast.select.append(self._parse_select_item())

    def _parse_select_item(self) -> Union[ColumnRef, AggFunc]:
        tok = self._current()
        if tok.value in ('COUNT', 'SUM', 'AVG', 'MIN', 'MAX'):
            self._advance()
            self._expect(TokenType.PUNCTUATION, '(')
            col = self._parse_column_or_star()
            self._expect(TokenType.PUNCTUATION, ')')
            return AggFunc(func=tok.value, column=col)
        return self._parse_column()

    def _parse_column(self) -> ColumnRef:
        table, name = None, None
        if self._current().type == TokenType.IDENTIFIER:
            table = self._advance().value
            if self._current().type == TokenType.PUNCTUATION and self._current().value == '.':
                self._advance()
                name = self._expect(TokenType.IDENTIFIER).value
            else:
                name = table
                table = None
        else:
            raise SyntaxError(f"Expected column name, got '{self._current().value}'", self._current().pos)
        return ColumnRef(table=table, name=name)

    def _parse_column_or_star(self) -> Union[ColumnRef, str]:
        if self._current().type == TokenType.PUNCTUATION and self._current().value == '*':
            self._advance()
            return "*"
        return self._parse_column()

    def _parse_from(self, ast: QueryAST):
        self._expect(TokenType.KEYWORD, 'FROM')
        ast.from_table = self._expect(TokenType.IDENTIFIER).value

    def _parse_join(self, ast: QueryAST):
        # Support INNER JOIN
        if self._match('INNER'):
            pass
        self._expect(TokenType.KEYWORD, 'JOIN')
        join_table = self._expect(TokenType.IDENTIFIER).value
        self._expect(TokenType.KEYWORD, 'ON')
        condition = self._parse_condition()
        ast.join = (join_table, condition)

    def _parse_where(self, ast: QueryAST):
        ast.where = self._parse_condition()

    def _parse_condition(self) -> Condition:
        left = self._parse_condition_value()
        op = self._expect(TokenType.OPERATOR).value
        right = self._parse_condition_value()
        return Condition(left=left, op=op, right=right, is_in=(op.upper() == 'IN'))

    def _parse_condition_value(self) -> Union[ColumnRef, str, int, float]:
        tok = self._current()
        if tok.type == TokenType.IDENTIFIER:
            return self._parse_column()
        if tok.type == TokenType.STRING:
            self._advance()
            return tok.value
        if tok.type == TokenType.NUMBER:
            self._advance()
            return tok.value
        if tok.type == TokenType.PUNCTUATION and tok.value == '(':
            self._advance()
            val = self._parse_condition_value()
            self._expect(TokenType.PUNCTUATION, ')')
            return val
        raise SyntaxError(f"Unexpected token in condition: '{tok.value}'", tok.pos)

    def _parse_group_by(self, ast: QueryAST):
        ast.group_by.append(self._parse_column())
        while self._current().type == TokenType.PUNCTUATION and self._current().value == ',':
            self._advance()
            ast.group_by.append(self._parse_column())

    def _parse_order_by(self, ast: QueryAST):
        col = self._parse_column()
        direction = 'ASC'
        if self._current().type == TokenType.KEYWORD and self._current().value in ('ASC', 'DESC'):
            direction = self._advance().value
        ast.order_by.append((col, direction))
        while self._current().type == TokenType.PUNCTUATION and self._current().value == ',':
            self._advance()
            col = self._parse_column()
            direction = 'ASC'
            if self._current().type == TokenType.KEYWORD and self._current().value in ('ASC', 'DESC'):
                direction = self._advance().value
            ast.order_by.append((col, direction))

    def _parse_limit(self, ast: QueryAST):
        tok = self._expect(TokenType.NUMBER)
        ast.limit = int(tok.value)
        if ast.limit < 0:
            raise SyntaxError("LIMIT must be non-negative", tok.pos)

# ==========================
# 5. VALIDATOR
# ==========================
class Validator:
    def __init__(self, datasets: Dict[str, List[Dict[str, Any]]], schema: Dict[str, Dict[str, type]]):
        self.datasets = datasets
        self.schema = schema
        self.errors: List[str] = []

    def validate(self, ast: QueryAST) -> bool:
        self.errors = []

        if not ast.from_table:
            self.errors.append("FROM clause is required")
            return False

        if ast.from_table not in self.schema:
            self.errors.append(f"Table '{ast.from_table}' not found")

        if ast.join:
            join_table, _ = ast.join
            if join_table not in self.schema:
                self.errors.append(f"Join table '{join_table}' not found")

        has_agg = any(isinstance(item, AggFunc) for item in ast.select)
        has_group = bool(ast.group_by)

        if has_agg and not has_group:
            self.errors.append("Aggregation functions require a GROUP BY clause")
        elif has_group and not has_agg:
            self.errors.append("GROUP BY requires aggregation in SELECT")

        self._validate_columns(ast)
        return len(self.errors) == 0

    def _validate_columns(self, ast: QueryAST):
        # Validate SELECT columns
        for item in ast.select:
            if isinstance(item, AggFunc):
                if item.column != "*":
                    self._check_column_exists(item.column, ast)
            else:
                self._check_column_exists(item, ast)

        # Validate JOIN/WHERE conditions
        for cond, label in [(ast.join[1], "JOIN") if ast.join else (None, ""), (ast.where, "WHERE")]:
            if cond:
                if isinstance(cond.left, ColumnRef):
                    self._check_column_exists(cond.left, ast, label)
                if isinstance(cond.right, ColumnRef):
                    self._check_column_exists(cond.right, ast, label)

        # Validate GROUP BY columns
        for col in ast.group_by:
            self._check_column_exists(col, ast, "GROUP BY")

        # Validate ORDER BY columns
        for col, _ in ast.order_by:
            self._check_column_exists(col, ast, "ORDER BY")

    def _check_column_exists(self, col: ColumnRef, ast: QueryAST, context: str = "SELECT"):
        table = col.table or ast.from_table
        if table not in self.schema:
            return
        if col.name not in self.schema[table]:
            self.errors.append(f"{context} column '{col.name}' not found in table '{table}'")

# ==========================
# 6. EXECUTOR
# ==========================
class Executor:
    def __init__(self, datasets: Dict[str, List[Dict[str, Any]]]):
        self.datasets = datasets

    def execute(self, ast: QueryAST) -> List[Dict[str, Any]]:
        try:
            rows = self.datasets[ast.from_table].copy()

            if ast.join:
                rows = self._apply_join(rows, ast.join, ast.from_table)
            if ast.where:
                rows = self._apply_where(rows, ast.where, ast.from_table)
            if ast.group_by:
                rows = self._apply_group_by_and_aggregation(rows, ast.group_by, ast.select)
            else:
                rows = self._apply_select_projection(rows, ast.select, ast.from_table)
            if ast.order_by:
                rows = self._apply_order_by(rows, ast.order_by)
            if ast.limit is not None:
                rows = rows[:ast.limit]

            return rows
        except Exception as e:
            raise ExecutionError(f"Query execution failed: {str(e)}")

    def _resolve_col(self, row: Dict, col: ColumnRef, base_table: str) -> Any:
        table = col.table or base_table
        key = f"{table}.{col.name}" if col.table else col.name
        return row.get(key, row.get(col.name))

    def _apply_join(self, rows: List[Dict], join_info: Tuple[str, Condition], base_table: str) -> List[Dict]:
        join_table, condition = join_info
        join_rows = self.datasets[join_table].copy()
        result = []

        for r1 in rows:
            for r2 in join_rows:
                combined = {**r1, **{f"{join_table}.{k}": v for k, v in r2.items()}}
                if self._eval_condition(combined, condition, base_table):
                    result.append(combined)
        return result

    def _apply_where(self, rows: List[Dict], condition: Condition, base_table: str) -> List[Dict]:
        return [r for r in rows if self._eval_condition(r, condition, base_table)]

    def _eval_condition(self, row: Dict, cond: Condition, base_table: str) -> bool:
        left = self._resolve_col(row, cond.left, base_table) if isinstance(cond.left, ColumnRef) else cond.left
        right = self._resolve_col(row, cond.right, base_table) if isinstance(cond.right, ColumnRef) else cond.right

        op = cond.op.upper()
        try:
            if op == '=': return left == right
            if op == '!=': return left != right
            if op == '>': return left > right
            if op == '<': return left < right
            if op == '>=': return left >= right
            if op == '<=': return left <= right
            if op == 'IN': return left in right
            if op == 'LIKE': return str(left).lower().find(str(right).lower()) != -1
        except TypeError:
            return False
        return False

    def _apply_group_by_and_aggregation(self, rows: List[Dict], group_cols: List[ColumnRef], select_items: List) -> List[Dict]:
        groups: Dict[Tuple, List[Dict]] = {}
        for row in rows:
            key = tuple(self._resolve_col(row, c, "") for c in group_cols)
            groups.setdefault(key, []).append(row)

        result = []
        for key, group_rows in groups.items():
            row = {}
            for idx, col in enumerate(group_cols):
                row[col.name] = key[idx]

            for item in select_items:
                if isinstance(item, AggFunc):
                    val = self._compute_agg(group_rows, item)
                    row[item.func.lower()] = val
                else:
                    row[item.name] = key[0]  # Already grouped
            result.append(row)
        return result

    def _compute_agg(self, rows: List[Dict], agg: AggFunc) -> Any:
        if agg.column == "*":
            return len(rows) if agg.func == "COUNT" else 0
        values = [self._resolve_col(r, agg.column, "") for r in rows]
        values = [v for v in values if v is not None]
        if not values:
            return 0
        if agg.func == "SUM": return sum(values)
        if agg.func == "AVG": return statistics.mean(values)
        if agg.func == "MIN": return min(values)
        if agg.func == "MAX": return max(values)
        return len(values)

    def _apply_select_projection(self, rows: List[Dict], select_items: List, base_table: str) -> List[Dict]:
        result = []
        for row in rows:
            projected = {}
            for item in select_items:
                if isinstance(item, ColumnRef):
                    projected[item.name] = self._resolve_col(row, item, base_table)
                else:
                    # Agg without GROUP BY is invalid per validator, but handled safely
                    pass
            result.append(projected)
        return result

    def _apply_order_by(self, rows: List[Dict], order_specs: List[Tuple[ColumnRef, str]]) -> List[Dict]:
        for col, direction in reversed(order_specs):
            reverse = direction == 'DESC'
            rows.sort(key=lambda r: r.get(col.name, float('-inf')), reverse=reverse)
        return rows

