class QueryEngine:
    def __init__(self, datasets: Dict[str, List[Dict[str, Any]]], schema: Dict[str, Dict[str, type]]):
        self.datasets = datasets
        self.schema = schema

    def query(self, sql: str) -> List[Dict[str, Any]]:
        try:
            lexer = Lexer(sql)
            ast = Parser(lexer.tokens).parse()

            validator = Validator(self.datasets, self.schema)
            if not validator.validate(ast):
                raise SemanticError("\n".join(validator.errors))

            return Executor(self.datasets).execute(ast)
        except (SyntaxError, SemanticError, ExecutionError):
            raise
        except Exception as e:
            raise ExecutionError(f"Unexpected error: {str(e)}")

