import re
from collections import defaultdict

class QueryParser:
    """
    A custom parser for a simplified query language.

    Supported features:
        - Filtering: WHERE <column> <operator> <value>
        - Aggregation: GROUP BY <column>, <AGGREGATE_FUNCTION>(<column>) AS <alias>
        - Joining: JOIN <table2> ON <column1> = <column2>
        - Selection: SELECT <column1>, <column2>, ...

    Supported aggregate functions: COUNT, SUM, AVG, MAX, MIN
    Supported operators: =, !=, >, <, >=, <=
    """

    def __init__(self):
        self.data = {}  # Store datasets (tables)
        self.aggregate_functions = ["COUNT", "SUM", "AVG", "MAX", "MIN"]
        self.operators = ["=", "!=", ">", "<", ">=", "<="]

    def load_data(self, table_name, data):
        """Loads data into a table."""
        self.data[table_name] = data

    def parse(self, query):
        """Parses the query string and returns a query plan."""
        try:
            query = query.upper()
            select_clause, from_clause, where_clause, group_by_clause, join_clause = self._extract_clauses(query)

            query_plan = {
                "select": select_clause,
                "from": from_clause,
                "where": where_clause,
                "group_by": group_by_clause,
                "join": join_clause
            }

            self._validate_query_plan(query_plan)
            return query_plan
        except ValueError as e:
            return {"error": str(e)}

    def _extract_clauses(self, query):
        """Extracts the different clauses from the query string."""
        select_match = re.search(r"SELECT\s+(.+?)\s+(FROM|WHERE|GROUP BY|JOIN)", query)
        from_match = re.search(r"FROM\s+(.+?)\s+(WHERE|GROUP BY|JOIN|$)", query)
        where_match = re.search(r"WHERE\s+(.+?)\s+(GROUP BY|JOIN|$)", query)
        group_by_match = re.search(r"GROUP BY\s+(.+?)\s+(JOIN|$)", query)
        join_match = re.search(r"JOIN\s+(.+)", query)

        select_clause = select_match.group(1).split(",") if select_match else []
        from_clause = from_match.group(1).strip() if from_match else None
        where_clause = where_match.group(1).strip() if where_match else None
        group_by_clause = group_by_match.group(1).split(",") if group_by_match else []
        join_clause = join_match.group(1).strip() if join_match else None

        return select_clause, from_clause, where_clause, group_by_clause, join_clause

    def _validate_query_plan(self, query_plan):
        """Validates the query plan for correctness."""
        if not query_plan["from"]:
            raise ValueError("FROM clause is required.")

        if query_plan["from"] not in self.data:
            raise ValueError(f"Table '{query_plan['from']}' not found.")

        if query_plan["where"]:
            try:
                self._validate_where_clause(query_plan["where"])
            except ValueError as e:
                raise e

        if query_plan["group_by"]:
            for column in query_plan["group_by"]:
                if column not in self.data[query_plan["from"]][0]:
                    raise ValueError(f"Column '{column}' not found in table '{query_plan['from']}'.")

    def _validate_where_clause(self, where_clause):
        """Validates the WHERE clause."""
        match = re.match(r"(\w+)\s+(=|!=|>|<|>=|<=)\s+(.+)", where_clause)
        if not match:
            raise ValueError("Invalid WHERE clause format.")

        column, operator, value = match.groups()
        if operator not in self.operators:
            raise ValueError(f"Invalid operator: {operator}")

    def execute(self, query_plan):
        """Executes the query plan and returns the results."""
        try:
            table_name = query_plan["from"]
            data = self.data[table_name]

            # Apply WHERE clause
            if query_plan["where"]:
                data = self._apply_where_clause(data, query_plan["where"])

            # Apply JOIN clause (simplified - only one join supported)
            if query_plan["join"]:
                table2_name, join_condition = self._parse_join_clause(query_plan["join"])
                if table2_name not in self.data:
                    return {"error": f"Table '{table2_name}' not found."}
                table2_data = self.data[table2_name]
                data = self._apply_join_clause(data, table2_data, join_condition)

            # Apply GROUP BY clause
            if query_plan["group_by"]:
                data = self._apply_group_by_clause(data, query_plan["group_by"])

            # Select columns
            if query_plan["select"]:
                selected_data = []
                for row in data:
                    selected_row = {}
                    for column in query_plan["select"]:
                        selected_row[column] = row.get(column)
                    selected_data.append(selected_row)
                return selected_data
            else:
                return data
        except Exception as e:
            return {"error": str(e)}

    def _apply_where_clause(self, data, where_clause):
        """Applies the WHERE clause to the data."""
        match = re.match(r"(\w+)\s+(=|!=|>|<|>=|<=)\s+(.+)", where_clause)
        if not match:
            raise ValueError("Invalid WHERE clause format.")

        column, operator, value = match.groups()

        filtered_data = []
        for row in data:
            if operator == "=":
                if row.get(column) == value:
                    filtered_data.append(row)
            elif operator == "!=":
                if row.get(column) != value:
                    filtered_data.append(row)
            elif operator == ">":
                if row.get(column) > float(value):
                    filtered_data.append(row)
            elif operator == "<":
                if row.get(column) < float(value):
                    filtered_data.append(row)
            elif operator == ">=":
                if row.get(column) >= float(value):
                    filtered_data.append(row)
            elif operator == "<=":
                if row.get(column) <= float(value):
                    filtered_data.append(row)
        return filtered_data

    def _parse_join_clause(self, join_clause):
        """Parses the JOIN clause."""
        match = re.match(r"(\w+)\s+ON\s+(.+)", join_clause)
        if not match:
            raise ValueError("Invalid JOIN clause format.")
        table2_name = match.group(1)
        join_condition = match.group(2)
        return table2_name, join_condition

    def _apply_join_clause(self, data1, data2, join_condition):
        """Applies the JOIN clause to the data."""
        match = re.match(r"(\w+)\s+=\s+(\w+)", join_condition)
        if not match:
            raise ValueError("Invalid JOIN condition format.")
        column1, column2 = match.groups()

        joined_data = []
        for row1 in data1:
            for row2 in data2:
                if row1.get(column1) == row2.get(column2):
                    new_row = row1.copy()
                    new_row.update(row2)
                    joined_data.append(new_row)
        return joined_data

    def _apply_group_by_clause(self, data, group_by_columns):
        """Applies the GROUP BY clause to the data."""
        grouped_data = defaultdict(list)
        for row in data:
            key = tuple(row.get(col) for col in group_by_columns)
            grouped_data[key].append(row)

        aggregated_data = []
        for key, rows in grouped_data.items():
            aggregated_row = {}
            for col in group_by_columns:
                aggregated_row[col] = key[group_by_columns.index(col)]

            # Perform aggregation (simplified - only one aggregate function per group)
            for row in rows:
                for col, value in row.items():
                    if col not in group_by_columns:
                        if col in aggregated_row:
